#include<bits/stdc++.h>
using namespace std;
bool c[1000000001];
int b[100000001],k=0,n,a[11][11],x,y;
int main(){
	cin>>n>>x>>y;
	for(int i=2;k<=n*n;i++){
		if(!c[i]){
			b[k++]=i;
		}for(int j=0;j<k;j++){
			c[i*b[j]]=1;
			if(i%b[j]==0){
				break;
			}
		}
	}


	int  i = 1, j = 0, num = 1;
	while (num <= n * n) {

		while (a[i][++j] == 0 && j <= n) {
			a[i][j] = b[num++-1];
		}
		j--;
		while (a[++i][j] == 0 && i <= n) {
			a[i][j] = b[num++-1];
		}
		i--;
		while (a[i][--j] == 0 && j >= 1) {
			a[i][j] = b[num++-1];
		}
		j++;
		while (a[--i][j] == 0 && i >= 1) {
			a[i][j] = b[num++-1];
		}
		i++;
	}
	cout<<a[x][y];
	return 0;
}
